import{_ as a,o as t,c as r,af as i}from"./chunks/framework.BSym9njW.js";const g=JSON.parse('{"title":"Torch-RecHub Recommender Systems Practice","description":"","frontmatter":{},"headers":[],"relativePath":"05-amd-yes/torch-rechub/index.md","filePath":"en/05-amd-yes/torch-rechub/index.md","lastUpdated":1778553795000}'),o={name:"05-amd-yes/torch-rechub/index.md"};function n(s,e,l,h,c,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="torch-rechub-recommender-systems-practice" tabindex="-1">Torch-RecHub Recommender Systems Practice <a class="header-anchor" href="#torch-rechub-recommender-systems-practice" aria-label="Permalink to &quot;Torch-RecHub Recommender Systems Practice&quot;">​</a></h1><div align="center"><a href="https://pypi.org/project/torch-rechub/"><img alt="PyPI" src="https://img.shields.io/pypi/v/torch-rechub?style=for-the-badge&amp;color=005A9C&amp;label=torch-rechub"></a><a href="https://www.python.org/"><img alt="Python" src="https://img.shields.io/badge/python-3.9%2B-012A4A?style=for-the-badge"></a><a href="https://pytorch.org/"><img alt="PyTorch" src="https://img.shields.io/badge/pytorch-1.10%2B-EE4C2C?style=for-the-badge"></a><a href="https://rocm.docs.amd.com/"><img alt="ROCm" src="https://img.shields.io/badge/AMD%20ROCm-ready-ED1C24?style=for-the-badge"></a><a href="https://github.com/datawhalechina/torch-rechub"><img alt="GitHub stars" src="https://img.shields.io/github/stars/datawhalechina/torch-rechub?style=for-the-badge&amp;color=00C8FF"></a></div><p>This directory introduces practical recommender system workflows with <a href="https://github.com/datawhalechina/torch-rechub" target="_blank" rel="noreferrer">Torch-RecHub</a> on AMD GPU / ROCm environments. The goal is not only to run several models, but to understand how a modern recommendation pipeline is organized: feature definitions, data generators, trainers, ranking and matching models, experiment tracking, and model export for serving.</p><p>Torch-RecHub is a lightweight PyTorch recommender system framework designed to make industrial-style recommendation experiments easier to reproduce. It provides 30+ mainstream models across ranking, matching, multi-task learning, and generative recommendation, together with unified data loading, training, evaluation, tracking, and ONNX export utilities.</p><h2 id="why-it-is-here" tabindex="-1">Why It Is Here <a class="header-anchor" href="#why-it-is-here" aria-label="Permalink to &quot;Why It Is Here&quot;">​</a></h2><p>In hello-rocm, this case focuses on the AMD GPU side of recommender systems. You will learn how to install ROCm-compatible PyTorch, run Torch-RecHub tutorials on AMD hardware, and connect model training with deployment-oriented steps such as ONNX export and lightweight retrieval validation.</p><p>The tutorials use small sample datasets so the full workflow can be tested locally. The metrics are for pipeline validation rather than production benchmarking.</p><h2 id="what-you-will-learn" tabindex="-1">What You Will Learn <a class="header-anchor" href="#what-you-will-learn" aria-label="Permalink to &quot;What You Will Learn&quot;">​</a></h2><ul><li>How CTR ranking models such as DeepFM turn dense and sparse features into click-through-rate predictions.</li><li>How DIN models user behavior sequences with target-aware attention.</li><li>How DSSM builds a two-tower matching model and uses item embeddings for retrieval.</li><li>How MMOE shares experts across multiple recommendation objectives.</li><li>How Torch-RecHub connects WandB, SwanLab, and TensorBoardX through a unified <code>model_logger</code> interface.</li><li>How trained ranking and matching models can be exported to ONNX and validated with ONNXRuntime.</li></ul><h2 id="torch-rechub-highlights" tabindex="-1">Torch-RecHub Highlights <a class="header-anchor" href="#torch-rechub-highlights" aria-label="Permalink to &quot;Torch-RecHub Highlights&quot;">​</a></h2><ul><li><strong>PyTorch-first design</strong>: uses PyTorch dynamic graphs and hardware acceleration, including CPU, NVIDIA CUDA GPU, AMD ROCm GPU, and Huawei Ascend NPU.</li><li><strong>Rich model library</strong>: includes 30+ recommendation models covering ranking, matching, multi-task learning, and generative recommendation.</li><li><strong>Modular components</strong>: feature definitions, layers, trainers, losses, metrics, and utilities are separated so models and datasets can be extended.</li><li><strong>Standardized workflow</strong>: provides unified data loading, training, evaluation, experiment tracking, and model export paths.</li><li><strong>Deployment awareness</strong>: supports ONNX export and serving-oriented validation, making it easier to move from training to inference.</li><li><strong>Experiment tracking</strong>: integrates WandB, SwanLab, and TensorBoardX through a consistent logging interface.</li></ul><h2 id="tutorials" tabindex="-1">Tutorials <a class="header-anchor" href="#tutorials" aria-label="Permalink to &quot;Tutorials&quot;">​</a></h2><ol><li><a href="/hello-rocm/05-amd-yes/torch-rechub/00_QuickStart_CTR_DeepFM">CTR Prediction: DeepFM</a></li><li><a href="/hello-rocm/05-amd-yes/torch-rechub/01_Ranking_DIN">Sequential Interest Modeling: DIN</a></li><li><a href="/hello-rocm/05-amd-yes/torch-rechub/02_Matching_DSSM">Matching / Retrieval: DSSM</a></li><li><a href="/hello-rocm/05-amd-yes/torch-rechub/03_MultiTask_MMOE">Multi-task Learning: MMOE</a></li><li><a href="/hello-rocm/05-amd-yes/torch-rechub/04_Experiment_Tracking_Light">Experiment Tracking: model_logger</a></li><li><a href="/hello-rocm/05-amd-yes/torch-rechub/05_Model_Export_and_Serving">Model Export and Inference Validation: ONNX</a></li></ol>',13)])])}const u=a(o,[["render",n]]);export{g as __pageData,u as default};
